var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"핫핫핫, 도와줘서 고맙군.","JPN":"ハハハ、助けてくれてありがとう。","ENG":"Gah hah hah, much appreciated.","TWN":"哈哈哈，多謝你的幫忙。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"물건을 찾고 있었는데 갑자기 침식체가 꼬여서 말이야.","JPN":"物を探していたが、いきなり侵食体にからまれたのだ。","ENG":"I was looking for something and found some C.O.s instead.","TWN":"我正在找東西，結果侵蝕體突然冒出來。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"감사인사는 됐어. 당신들이 죽게 뒀으면 어차피 우리한테 꼬였을 테니까.","JPN":"お礼はいい。あなたたちが死んでたらどうせあたしたちに来ていたはずだし。","ENG":"Don't worry about it. They would've come to us if we let you die.","TWN":"不用謝，要是你們死了，我們就會被盯上。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"뭐, 그럼- 고마운 건 고마운 거고….","JPN":"まぁ、じゃーありがたいのはさておき……","ENG":"Well, then. I've said my thanks, so...","TWN":"不管怎麼說，還是要謝謝你們…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…가진 게 있다면 넘겨주실까?","JPN":"……持っているものがあるなら、渡してもらおうか？","ENG":"...Hand over what you've got.","TWN":"…不如把你身上的東西交出來吧？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"특별히 필요한 거라도 있나?","JPN":"特別に必要な物でもあるのか？","ENG":"Is there anything in particular you need?","TWN":"你需要什麼？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신들이 타고 온 배.","JPN":"あなたたちが乗ってきた船。","ENG":"The ship that you brought here.","TWN":"你們乘坐的那艘船。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"인연이군. 이쪽도 너희 배가 필요하거든.","JPN":"奇遇だな、こっちも君たちの船が必要だ。","ENG":"What a coincidence. We need your ship too.","TWN":"這麼巧，我們也需要你們的船。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신들 게 더 컸으면 좋겠네. 난 공정한 배팅은 싫어해서.","JPN":"あなたたちの船の方が大きいことを願うよ。あたしは不公正な取引が好きなんだ。","ENG":"I hope your ship is bigger. I'm not too keen on a fair trade.","TWN":"我希望你的賭注再大一點，我不喜歡公平的賭注。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"핫핫핫! 칼솜씨가 제법 좋군. 어디서 배운 건가?","JPN":"ハハハ！　良い腕だな。どこで習った？","ENG":"Gah hah hah! You're pretty good with that knife. Where did you learn how to use it?","TWN":"哈哈哈！刀法不錯，你從哪裡學的？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"시장에서 생선 손질을 배웠지. 부둣가에서 생선 장사를 했거든.","JPN":"市場で魚をさばきながら習った。港で魚を売っていたんだ。","ENG":"I learned how to handle fish at the market. I used to sell fish at the dockside.","TWN":"我在市場殺魚時學的，我曾經在碼頭賣過魚。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"…음? 생선이라고…?","JPN":"……ん？　魚だと……？","ENG":"...Hmm? Fish...?","TWN":"…嗯？賣魚…？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"맞혔다!","JPN":"当たった！","ENG":"Got him!","TWN":"打中了！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"콜록 콜록.","JPN":"ゲホッゲホッ。","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"야, 나까지 맞을 뻔 했잖아.","JPN":"こら、あたしまで当たるところだったじゃん。","ENG":"Hey, you almost hit me too.","TWN":"喂，你差點打到我。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"정말이지- 소냐는 동료에 대한 신뢰가 부족하다니까요.","JPN":"全くー、ソーニャは仲間に対する信頼が足りませんね。","ENG":"Oh, Sonya. You need to have more faith in your crew mates.","TWN":"真是的，索妮雅就是缺乏對夥伴的信任。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"으엣? 어째서 제 목덜미에 칼이…?","JPN":"うえ？　何で私の首に刃が……？","ENG":"Eek? Why is there a blade to my throat...?","TWN":"嗯？為什麼有一把刀架在我的脖子上…？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}}]`);export{e as default};